def _split_parts(text):
    cleaned = text.replace("/", " ").replace("-", " ")
    return [part for part in cleaned.split() if part]


def _parse_pairs(raw):
    return [tuple(part.split("=", 1)) for part in raw.split("|") if part]


def _make_daily_entry(idx, level, cat, icon, word, tr, wt="word"):
    return {
        "id": idx,
        "mod": "daily",
        "level": level,
        "cat": cat,
        "icon": icon,
        "word": word,
        "syl": _split_parts(word),
        "ph": "",
        "wt": wt,
        "tr": tr,
        "tpl": "Use ___ in a daily sentence.",
        "sent": f"I often use <strong>{word}</strong> in daily English.",
        "str": "S+V+O",
        "rel": [],
        "why": f"{word} is useful in everyday conversations.",
        "da": f"Can you use {word} in a sentence?",
        "db": f"Yes — {word} means {tr.lower()}."
    }


