def _build_extra_daily_words():
    items = []
    next_id = 301
    for level, cat, icon, raw in _DAILY_EXTRA_GROUPS:
        for word, tr in _parse_pairs(raw):
            items.append(_make_daily_entry(next_id, level, cat, icon, word, tr))
            next_id += 1
    return items


WORDS.extend(_build_extra_daily_words())
assert len([w for w in WORDS if w["mod"] == "daily"]) == 600, f"Expected 600 daily words, found {len([w for w in WORDS if w['mod'] == 'daily'])}"

# ── YARDIMCI FONKSİYONLAR ──────────────────────────────

def get_all():
    return WORDS

def get_by_mod(mod):
    """cs veya daily"""
    return [w for w in WORDS if w['mod'] == mod]

def get_by_level(level):
    """A1, A2, B1, B2, C1"""
    return [w for w in WORDS if w['level'] == level]

def get_by_mod_level(mod, level):
    return [w for w in WORDS if w['mod'] == mod and w['level'] == level]

def get_by_cat(cat):
    return [w for w in WORDS if w['cat'] == cat]

def get_cats(mod=None):
    ws = WORDS if not mod else get_by_mod(mod)
    return list(set(w['cat'] for w in ws))

def get_levels(mod=None):
    ws = WORDS if not mod else get_by_mod(mod)
    order = ['A1','A2','B1','B2','C1']
    found = set(w['level'] for w in ws)
    return [l for l in order if l in found]

def get_stats():
    total = len(WORDS)
    cs = len(get_by_mod('cs'))
    daily = len(get_by_mod('daily'))
    by_level = {l: len(get_by_level(l)) for l in ['A1','A2','B1','B2','C1']}
    return {
        'total': total,
        'cs': cs,
        'daily': daily,
        'by_level': by_level
    }
